Here's a modern MSTest 3.x test class covering success, failure, timeout, and cancellation:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    private static (DataFetcher fetcher, FakeHandler handler) CreateFetcher(
        Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> sendFunc)
    {
        var handler = new FakeHandler(sendFunc);
        var client = new HttpClient(handler);
        return (new DataFetcher(client), handler);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        var (fetcher, handler) = CreateFetcher((_, _) =>
            Task.FromResult(new HttpResponseMessage(HttpStatusCode.OK)
            {
                Content = new StringContent("hello")
            }));

        var result = await fetcher.FetchAsync(
            "https://example.com", _testContext.CancellationToken);

        Assert.AreEqual("hello", result);
        handler.Dispose();
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ServerError_ThrowsHttpRequestException()
    {
        var (fetcher, handler) = CreateFetcher((_, _) =>
            Task.FromResult(new HttpResponseMessage(HttpStatusCode.InternalServerError)));

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync(
                "https://example.com", _testContext.CancellationToken));

        handler.Dispose();
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_CancellationRequested_ThrowsTaskCanceledException()
    {
        using var cts = new CancellationTokenSource();
        var (fetcher, handler) = CreateFetcher(async (_, ct) =>
        {
            await Task.Delay(Timeout.Infinite, ct); // blocks until cancelled
            return new HttpResponseMessage(); // never reached
        });

        cts.Cancel();

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));

        handler.Dispose();
    }

    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_SlowResponse_CancelledByTimeout()
    {
        var (fetcher, handler) = CreateFetcher(async (_, ct) =>
        {
            await Task.Delay(Timeout.Infinite, ct);
            return new HttpResponseMessage();
        });

        // TestContext.CancellationToken fires when [Timeout] expires,
        // so passing it through tests cooperative timeout cancellation.
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync(
                "https://example.com", _testContext.CancellationToken));

        handler.Dispose();
    }

    /// <summary>Minimal delegating handler for tests — no mocking library needed.</summary>
    private sealed class FakeHandler(
        Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> sendFunc)
        : HttpMessageHandler
    {
        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
            => sendFunc(request, cancellationToken);
    }
}
```

**Key patterns used:**

| Pattern | Why |
|---|---|
| `TestContext` via constructor | Enables `readonly` field, satisfies nullability |
| `[Timeout]` + `_testContext.CancellationToken` | Cooperative timeout — MSTest cancels the token when time expires |
| Separate `CancellationTokenSource` | Tests caller-initiated cancellation independently from timeout |
| `Assert.ThrowsExactlyAsync<T>` | Modern pattern — replaces `[ExpectedException]`, allows inspecting the exception |
| `FakeHandler` | Avoids mocking libraries; gives full control over `HttpClient` behavior |
| `sealed` test class | MSTest best practice for performance |

The critical insight: **pass `_testContext.CancellationToken`** to your async calls in tests with `[Timeout]`. This is how MSTest cooperatively cancels your test — without it, the timeout can't interrupt the async operation cleanly.
